import React, { useState } from 'react';
import ImportDataSidebar from './ImportDataSidebar'; // Importing the sidebar component
import './ChatBox.css';
import SideNav from './SideNav';
import { useNavigate } from 'react-router-dom'; // Import useNavigate from react-router-dom

function ChatBox() {
  const [userStory, setUserStory] = useState(''); // User story entered by the user
  const [messages, setMessages] = useState([]); // Array of messages to display in the chat
  const [isSidebarVisible, setIsSidebarVisible] = useState(false); // Whether the sidebar is visible
  const [jiraData, setJiraData] = useState([]); // Data fetched from Jira
  const [isAuthenticated, setIsAuthenticated] = useState(true); // Manage login state
  const [isProcessing, setIsProcessing] = useState(false); // Track if we're processing a request
  const navigate = useNavigate(); // Initialize the navigate function

  // Handle logout (simulate logout)
  const logout = () => {
    setIsAuthenticated(false);
    navigate('/Login'); // Navigate to the Login page after logout
  };

  // Function to send user story and get generated test cases from C# backend
  const generateTestCases = async (userStory) => {
    setIsProcessing(true); // Set processing to true while generating test cases
    try {
      const response = await fetch('https://localhost:7216/api/UserStoryDescription/GenerateTestCases', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ userStory }), // Sending the userStory in the body
      });
  
      if (!response.ok) {
        throw new Error(`Failed to generate test cases. Status code: ${response.status}`);
      }
  
      const data = await response.json();
      console.log('Generated test cases:', data); // Log the full response for debugging
  
      // Check if the response has the expected structure
      const candidates = data.candidates;
      if (candidates && candidates.length > 0) {
        const testCaseContent = candidates[0].content.parts.map(part => part.text).join('\n');
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: `Generated test cases:\n${testCaseContent}`, isUserMessage: false },
        ]);
      } else {
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: 'No test cases found.', isUserMessage: false },
        ]);
      }
    } catch (error) {
      console.error('Error generating test cases:', error);
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: `Error generating test cases. Error: ${error.message}`, isUserMessage: false },
      ]);
    } finally {
      setIsProcessing(false); // Reset processing state
    }
  };

  // Handle message input from user
  const handleMessageChange = (e) => {
    setUserStory(e.target.value);
  };

  // Handle sending the user story message (chat-like)
  const handleSendMessage = () => {
    if (userStory.trim()) {
      // Add the user's message to the messages state
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: userStory, isUserMessage: true },
      ]);
      setUserStory(''); // Clear the input field

      // After sending the message, call the generateTestCases function
      generateTestCases(userStory);  // Call the function to generate test cases
    }
  };

  // Fetch multiple user stories from Jira using a hardcoded URL
  const handleImportData = async () => {
    const backendUrl = 'https://localhost:7216/api/UserStoryDescription/ExportAllUserStories';
  
    try {
      const response = await fetch(backendUrl, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
        },
      });
  
      if (!response.ok) {
        throw new Error('Failed to fetch data from backend');
      }
  
      const data = await response.json();
      const stories = data.map(issue => ({
        id: issue.key,
        story: issue.summary,
      }));
  
      setJiraData(stories); // Store the fetched Jira stories
      setIsSidebarVisible(true); // Show the sidebar
  
      // Generate test cases for each story
      stories.forEach(story => {
        generateTestCases(story.story);
      });
  
    } catch (error) {
      console.error('Error fetching Jira data:', error);
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: 'Error fetching Jira data. Please try again later.', isUserMessage: false },
      ]);
    }
  };

  // Handle selecting a user story from the sidebar
  const handleSelectUserStory = (story) => {
    // Instead of directly modifying messages, use the functional setter to ensure proper state update
    setMessages((prevMessages) => [
      ...prevMessages,
      { text: story.story, isUserMessage: false },
    ]);
    
    // Generate test cases for the selected user story
    generateTestCases(story.story); // Generate test cases for the selected story
  };

  // Handle closing the sidebar
  const handleCloseSidebar = () => {
    setIsSidebarVisible(false); // Close the sidebar
  };

  return (
    <div className="chat-container">
      {/* Render SideNav only if authenticated */}
      {isAuthenticated && <SideNav logout={logout} />} {/* Pass logout to SideNav */}

      {/* Chat box UI */}
      <div className="chat-box">
        <div className="chat-box-messages">
          {messages.map((message, index) => (
            <div
              key={index}
              className={`message ${message.isUserMessage ? 'user-message' : 'bot-message'}`}
            >
              {message.text}
            </div>
          ))}
        </div>
        <div className="chat-input-container">
          <textarea
            value={userStory}
            onChange={handleMessageChange}
            placeholder="Enter your Jira User Story URL here..."
            rows="4"
            disabled={isProcessing}  // Disable input while processing
          />
          <button onClick={handleSendMessage} disabled={isProcessing}>Send</button>
        </div>
      </div>

      {/* Sidebar for importing Jira data */}
      {isSidebarVisible && (
        <ImportDataSidebar
          jiraData={jiraData}
          onSelectUserStory={handleSelectUserStory}
          onClose={handleCloseSidebar} // Pass close handler to sidebar
          isSidebarVisible={isSidebarVisible} // Pass visibility prop
        />
      )}

      {/* Button to import data from Jira */}
      <button className="import-btn" onClick={handleImportData} disabled={isProcessing}>
        Import Data from Jira
      </button>
    </div>
  );
}

export default ChatBox;
